# -*- coding: utf-8 -*-
"""Generate HLSL per pass from its binding/access list. One source cross-compiles
to SPIR-V (Vulkan), DXIL (D3D12) and DXBC (D3D11) via the VKB() macro, which
fixes the Vulkan set/binding only; D3D paths use the register slots. The access
column of each binding decides exactly which load/store the bytecode contains,
so the viewer's shader-parse refinement has a precise ground truth to reproduce.
Python 3.6. See the access matrix in the design spec."""

from . import schema as S
from .layout import assign

HEADER = """\
// AUTO-GENERATED by gen/hlsl_codegen.py -- do not edit.
#ifdef __spirv__
#define VKB(b, s) [[vk::binding(b, s)]]
#define VLOC(n) [[vk::location(n)]]
#else
#define VKB(b, s)
#define VLOC(n)
#endif
"""


def _decl(slot):
    """Resource declaration line for one binding."""
    b, ident, reg = slot['bind'], slot['ident'], slot['hlsl_reg']
    vkb = 'VKB(%d, 0) ' % slot['vk_binding']
    if b == S.BIND_SRV_BUF:
        return '%sStructuredBuffer<uint>   %s : register(%s);' % (vkb, ident, reg)
    if b == S.BIND_UAV_BUF:
        return '%sRWStructuredBuffer<uint> %s : register(%s);' % (vkb, ident, reg)
    if b == S.BIND_UAV_TEX:
        return '%sRWTexture2D<float4>      %s : register(%s);' % (vkb, ident, reg)
    if b == S.BIND_CBV:
        # a one-line constant buffer block; the member is read by name. CBVs are
        # read-only, so this only ever produces a load (never a store).
        return '%scbuffer cb_%s : register(%s) { uint %s_cv; };' % (
            vkb, ident, reg, ident)
    raise ValueError('compute decl: unsupported bind %r' % b)


def _read_expr(slot):
    """An expression that loads from the binding (keeps it a READ)."""
    b, ident = slot['bind'], slot['ident']
    if b in (S.BIND_SRV_BUF, S.BIND_UAV_BUF):
        return '%s[i]' % ident
    if b == S.BIND_UAV_TEX:
        return '(uint)%s[uint2(i & 63u, (i >> 6u) & 63u)].x' % ident
    if b == S.BIND_CBV:
        return '%s_cv' % ident
    raise ValueError('read: unsupported bind %r' % b)


def _none_stmt(slot):
    """Reference the resource via metadata only -- keeps it in reflection without
    a load/store, so the parser classifies it UNUSED. (POC-verified.)"""
    b, ident = slot['bind'], slot['ident']
    if b in (S.BIND_SRV_BUF, S.BIND_UAV_BUF):
        return '    { uint _n, _s; %s.GetDimensions(_n, _s); acc += _n; }' % ident
    if b == S.BIND_UAV_TEX:
        return '    { uint _w, _h; %s.GetDimensions(_w, _h); acc += _w; }' % ident
    raise ValueError('none: unsupported bind %r' % b)


def gen_compute(p):
    """schema.Pass -> compute HLSL string."""
    slots = assign(p.binds)
    reads = [s for s in slots if s['access'] == S.ACC_READ]
    rws = [s for s in slots if s['access'] == S.ACC_RW]
    writes = [s for s in slots if s['access'] == S.ACC_WRITE]
    nones = [s for s in slots if s['access'] == S.ACC_NONE]

    body = ['[numthreads(64, 1, 1)]',
            'void main(uint3 tid : SV_DispatchThreadID) {',
            '    uint i = tid.x;',
            '    uint acc = 0;']
    for s in reads:
        body.append('    acc += %s;' % _read_expr(s))
    for s in nones:
        body.append(_none_stmt(s))
    for s in rws:
        if s['bind'] == S.BIND_UAV_TEX:
            xy = 'uint2(i & 63u, (i >> 6u) & 63u)'
            body.append('    %s[%s] = %s[%s] + float4(acc, 0, 0, 1);'
                        % (s['ident'], xy, s['ident'], xy))
        elif s.get('atomic'):
            # atomic read-modify-write: still classified rw, but exercises the
            # parser's InterlockedAdd recognition path
            body.append('    { uint _old; InterlockedAdd(%s[0], acc + 1u, _old); }'
                        % s['ident'])
        else:
            body.append('    %s[i] = %s[i] + acc + 1u;'
                        % (s['ident'], s['ident']))
    for s in writes:
        if s['bind'] == S.BIND_UAV_TEX:
            body.append('    %s[uint2(i & 63u, (i >> 6u) & 63u)] = float4(acc, 0, 0, 1);'
                        % s['ident'])
        else:
            body.append('    %s[i] = acc + i * 2u;' % s['ident'])
    body.append('}')

    decls = [_decl(s) for s in slots]
    return HEADER + '\n' + '\n'.join(decls) + '\n\n' + '\n'.join(body) + '\n'


# ---- graphics: fullscreen-triangle VS + sampling/output PS ----

_VS = """\
// AUTO-GENERATED by gen/hlsl_codegen.py -- do not edit.
void main(uint vid : SV_VertexID, out float4 pos : SV_Position) {
    float2 p = float2(float((vid << 1) & 2), float(vid & 2));
    pos = float4(p * 2.0 - 1.0, 0.5, 1.0);
}
"""


def gen_vertex_graphics(p):
    """schema.Pass with vertex streams -> (vs_src, ps_src). The VS declares one
    float4 input attribute per stream (ATTR0.. / vk::location N, slot N), so the
    input assembler genuinely consumes every vertex buffer (a real VertexBuffer
    usage) and, with an index buffer, IndexBuffer. The PS writes a constant per
    color target; no sampling."""
    n = len(p.vertex)
    attrs = '\n'.join('    VLOC(%d) float4 a%d : ATTR%d;' % (i, i, i)
                      for i in range(n))
    vsum = ' + '.join('v.a%d' % i for i in range(n)) or 'float4(0,0,0,1)'
    vs = (HEADER + '\nstruct VIn {\n' + attrs + '\n};\n' +
          '\nfloat4 main(VIn v) : SV_Position {\n    return ' + vsum + ';\n}\n')

    ncolor = max(1, len(p.color))
    out_fields = '\n'.join('    float4 c%d : SV_Target%d;' % (i, i)
                           for i in range(ncolor))
    psbody = '\n'.join('    o.c%d = float4(1, 1, 1, 1);' % i for i in range(ncolor))
    ps = (HEADER + '\nstruct PSOut {\n' + out_fields + '\n};\n' +
          '\nPSOut main(float4 pos : SV_Position) {\n    PSOut o;\n' +
          psbody + '\n    return o;\n}\n')
    return vs, ps


def gen_graphics(p):
    """schema.Pass -> (vs_src, ps_src). With vertex streams declared, delegate to
    gen_vertex_graphics (IA-driven draw). Otherwise the VS draws a fullscreen
    triangle from SV_VertexID (no IA) and the PS samples each `sample` SRV per its
    access (Load, no sampler), writing one value per color target; depth is
    governed by the depth-stencil state the runtime sets, not the shader."""
    if p.vertex:
        return gen_vertex_graphics(p)
    slots = assign(p.sample)
    decls = []
    for s in slots:
        vkb = 'VKB(%d, 0) ' % s['vk_binding']
        decls.append('%sTexture2D<float4> %s : register(%s);'
                     % (vkb, s['ident'], s['hlsl_reg']))

    ncolor = max(1, len(p.color))
    out_fields = '\n'.join('    float4 c%d : SV_Target%d;' % (i, i)
                           for i in range(ncolor))
    body = ['    PSOut o;', '    float4 acc = float4(0, 0, 0, 1);']
    for s in slots:
        if s['access'] == S.ACC_NONE:
            body.append('    { uint _w, _h; %s.GetDimensions(_w, _h); acc.x += (float)_w; }'
                        % s['ident'])
        else:
            body.append('    acc += %s.Load(int3(0, 0, 0));' % s['ident'])
    for i in range(ncolor):
        body.append('    o.c%d = acc;' % i)
    body.append('    return o;')

    ps = (HEADER + '\nstruct PSOut {\n' + out_fields + '\n};\n' +
          '\n'.join(decls) + ('\n' if decls else '') +
          '\nPSOut main(float4 pos : SV_Position) {\n' +
          '\n'.join(body) + '\n}\n')
    return _VS, ps
